function minsAfter(base,mins){return new Date(base.getTime()+mins*60000)}
function moonPhase(){
  const synodic=29.530588853, knownNew=Date.UTC(2000,0,6,18,14,0);
  let age=((Date.now()-knownNew)/86400000)%synodic; if(age<0) age+=synodic;
  const deg=age/synodic*360; return {deg, phase:deg<180?'Rising Moon':'Waning Moon', key:deg<180?'rising':'waning'};
}
function approxSunrise(lat,lon){
  const d=new Date(), zenith=90.8333;
  const N=Math.floor((Date.UTC(d.getFullYear(),d.getMonth(),d.getDate())-Date.UTC(d.getFullYear(),0,0))/86400000);
  const lngHour=lon/15,t=N+((6-lngHour)/24),M=(0.9856*t)-3.289;
  let L=M+(1.916*Math.sin(M*Math.PI/180))+(0.020*Math.sin(2*M*Math.PI/180))+282.634; L=(L+360)%360;
  let RA=Math.atan(0.91764*Math.tan(L*Math.PI/180))*180/Math.PI; RA=(RA+360)%360;
  RA=(RA+(Math.floor(L/90)*90-Math.floor(RA/90)*90))/15;
  const sinDec=0.39782*Math.sin(L*Math.PI/180), cosDec=Math.cos(Math.asin(sinDec));
  const cosH=(Math.cos(zenith*Math.PI/180)-sinDec*Math.sin(lat*Math.PI/180))/(cosDec*Math.cos(lat*Math.PI/180));
  if(cosH>1||cosH<-1)return new Date(d.getFullYear(),d.getMonth(),d.getDate(),6,0,0);
  const H=(360-Math.acos(cosH)*180/Math.PI)/15,T=H+RA-(0.06571*t)-6.622,UT=(T-lngHour+24)%24;
  const utc=new Date(Date.UTC(d.getFullYear(),d.getMonth(),d.getDate(),0,0,0)); utc.setUTCMinutes(Math.round(UT*60)); return utc;
}
function datasetKey(phase,period){
  if(phase==='Rising Moon' && period==='Day') return 'rising_day';
  if(phase==='Rising Moon' && period==='Night') return 'rising_night';
  if(phase==='Waning Moon' && period==='Day') return 'waning_day';
  return 'waning_night';
}
function currentPeriod(sr){
  const now=new Date(), night=minsAfter(sr,720);
  return (now>=sr && now<night) ? 'Day' : 'Night';
}
function dayTaNow(){ return DAY_ORDER_TA[new Date().getDay()]; }
function rowsForCurrentCycle(){
  const mp=moonPhase(), period=currentPeriod(state.sunrise), day=dayTaNow();
  const key=datasetKey(mp.phase,period);
  return APP.rows.filter(r=>r.dataset===key && r.day_ta===day);
}
function addTimes(rows){
  const period=currentPeriod(state.sunrise);
  const base = period==='Day'? state.sunrise : minsAfter(state.sunrise,720);
  let output=[];
  for(let samam=1; samam<=5; samam++){
    let cursor=minsAfter(base,(samam-1)*144);
    const group = rows.filter(r=>r.samam_en===`Samam ${samam}`);
    group.forEach((r,i)=>{
      const row={...r, from:cursor, to:minsAfter(cursor,r.minutes), index:i+1};
      row.duration=row.to-row.from;
      output.push(row);
      cursor=row.to;
    });
  }
  return output;
}
function getCurrent(){
  const rows = addTimes(rowsForCurrentCycle());
  const now=new Date();
  return rows.find(r=>now>=r.from && now<r.to) || rows[0];
}
function renderMicro(current){
  const grid=$('microGrid'), now=new Date(), partMs=current.duration/5;
  const activeIndex=Math.min(4,Math.max(0,Math.floor((now-current.from)/partMs)));
  grid.innerHTML='';
  for(let i=0;i<5;i++){
    const from=new Date(current.from.getTime()+partMs*i), to=new Date(current.from.getTime()+partMs*(i+1));
    const div=document.createElement('div');
    div.className=`micro ${i===activeIndex?'active':''}`;
    div.innerHTML=`Inner ${i+1}<small>${fmt(from)} → ${fmt(to)}</small>`;
    grid.appendChild(div);
  }
  $('innerText').textContent=`${activeIndex+1} / 5`;
}
function updateCurrent(){
  if(!state.sunrise || !APP) return;
  const current=getCurrent(), mp=moonPhase(), now=new Date();
  if(!current) return;
  state.current=current;
  state.context={phase:mp.phase,day:current.day_ta,period:current.period_en};
  const remain=current.to-now, progress=((now-current.from)/current.duration)*100;
  $('currentBox').classList.add('active');
  $('currentIcon').textContent=current.bird.icon;
  $('currentTitle').textContent=`${current.bird.name} · ${current.activity_en}`;
  $('currentPath').textContent=`${mp.phase} → ${current.day_en} → ${current.period_en} → ${current.samam_en} → ${current.activity_en} · ${fmt(current.from)} → ${fmt(current.to)}`;
  $('countdownText').textContent=`${hms(remain)} remaining`;
  $('activityBar').style.width=`${Math.min(100,Math.max(0,progress))}%`;
  $('moonText').textContent=`${mp.phase.replace(' Moon','')} ${mp.deg.toFixed(1)}°`;
  $('periodText').textContent=current.period_en;
  $('sunriseText').textContent=fmt(state.sunrise);
  renderMicro(current);
  renderActiveTree();
  renderAdhikara();
  renderPhaseWeekdays();
}
function birdBox(type,bird){
  const label=type==='adhikara'?'அதிகார பட்சி':'படு பட்சி';
  return `<div class="bird ${type}"><div class="img">${bird.icon}</div><div><div class="label">${label}</div><div class="name">${bird.name}</div></div></div>`;
}
function renderAdhikara(){
  const root=$('adhikaraRoot');
  if(!APP.adhikara || !APP.adhikara.length){root.innerHTML='<p class="lead">No Adhikara data found.</p>'; return;}
  root.innerHTML = ['Rising Moon','Waning Moon'].map(phase=>{
    const phaseRows=APP.adhikara.filter(x=>x.phase===phase), deg=phaseRows[0]?.deg||'';
    return `<div class="section" style="margin:0;border:0;box-shadow:none"><div class="section-head"><h2>${phase}</h2><span class="badge">${deg}</span></div><div class="day-grid">
    ${DAYS_EN.map(day=>{
      const rows=phaseRows.filter(x=>x.day_en===day), ta=rows[0]?.day_ta||day;
      const isToday=state.context&&state.context.phase===phase&&DAY_EN[state.context.day]===day;
      return `<article class="day-card ${isToday?'today':''}"><div class="day-title"><b>${day}</b><span>${ta}</span></div>
        ${['Day','Night'].map(period=>{
          const r=rows.find(x=>x.period===period); if(!r) return '';
          const isCurrent=isToday&&state.context.period===period;
          return `<div class="period ${isCurrent?'current-period':''}"><h3>${period} · ${r.period_ta}</h3><div class="bird-row">${birdBox('adhikara',r.adhikara)}${birdBox('padu',r.padu)}</div></div>`;
        }).join('')}
      </article>`;
    }).join('')}</div></div>`;
  }).join('');
}
function cardHTML(r, active=false, timed=false){
  return `<article class="card ${r.activity_cls} ${active?'active':''}" style="flex:${r.minutes}">
    <div class="bird-img" aria-hidden="true">${r.bird.icon}</div>
    <div class="meta"><span>${r.index || ''} / 5</span><span>${r.minutes} min</span></div>
    <div class="activity">${r.activity_icon} ${r.activity_en}</div>
    <div class="bird">${r.bird.name}</div>
    <div class="detail">
      <div class="box"><small>தமிழ்</small><b>${r.activity_ta}</b></div>
      <div class="box"><small>அட்சரம்</small><b>${r.atcharam || '--'}</b></div>
      <div class="box"><small>Moon</small><b>${r.phase_ta}</b></div>
      <div class="box"><small>Period</small><b>${r.period_ta}</b></div>
      ${timed?`<div class="box"><small>From</small><b>${fmt(r.from)}</b></div><div class="box"><small>To</small><b>${fmt(r.to)}</b></div>`:''}
    </div>
    <div class="timeline"><div class="fill" style="width:${Math.min(100,(r.minutes/48)*100)}%"></div></div>
  </article>`;
}
function renderActiveTree(){
  if(!state.sunrise) return;
  const root=$('activeTreeRoot'), rows=addTimes(rowsForCurrentCycle()), mp=moonPhase(), period=currentPeriod(state.sunrise), day=dayTaNow();
  root.innerHTML=`<div class="day-title"><b>${mp.phase} → ${DAY_EN[day]} → ${period}</b><span>Active day tree from location timing</span></div>`;
  for(let s=1;s<=5;s++){
    const items=rows.filter(r=>r.samam_en===`Samam ${s}`);
    const total=items.reduce((a,b)=>a+b.minutes,0);
    const div=document.createElement('div'); div.className='samam';
    div.innerHTML=`<div class="samam-title"><b>Samam ${s}</b><span>${total} min total</span></div><div class="card-row">${items.map((r,i)=>cardHTML({...r,index:i+1}, state.current&&r.from.getTime()===state.current.from.getTime(), true)).join('')}</div>`;
    root.appendChild(div);
  }
}
function renderFullTree(){
  const root=$('fullTreeRoot');
  const phases=[['Rising Moon',['rising_day','rising_night']],['Waning Moon',['waning_day','waning_night']]];
  root.innerHTML=phases.map(([phase,keys])=>`<details open><summary>${phase}</summary>
    ${keys.map(key=>{
      const period=key.includes('day')?'Day':'Night';
      return `<details><summary>${period}</summary>
        ${DAY_ORDER_TA.map(day=>{
          const rows=APP.rows.filter(r=>r.dataset===key && r.day_ta===day);
          return `<details><summary>${DAY_EN[day]} · ${day}</summary>
            ${[1,2,3,4,5].map(s=>{
              const items=rows.filter(r=>r.samam_en===`Samam ${s}`);
              return `<details><summary>Samam ${s}</summary><div class="card-row" style="padding:12px">${items.map((r,i)=>cardHTML({...r,index:i+1})).join('')}</div></details>`;
            }).join('')}
          </details>`;
        }).join('')}
      </details>`;
    }).join('')}
  </details>`).join('');
}

function findAdhikara(phase, dayTa, period='Day'){
  const dayEn = DAY_EN[dayTa];
  return (APP.adhikara||[]).find(x=>x.phase===phase && x.day_en===dayEn && x.period===period)
      || (APP.adhikara||[]).find(x=>x.phase===phase && x.day_en===dayEn)
      || null;
}
function phaseKey(phase, period){
  if(phase==='Rising Moon' && period==='Day') return 'rising_day';
  if(phase==='Rising Moon' && period==='Night') return 'rising_night';
  if(phase==='Waning Moon' && period==='Day') return 'waning_day';
  return 'waning_night';
}
function innerPartsHTML(minutes){
  const each = minutes / 5;
  return `<div class="inner-list">${[1,2,3,4,5].map(i=>`<div class="inner-mini">Inner ${i}<br><small>${each.toFixed(2)} min</small></div>`).join('')}</div>`;
}
function phaseWeekCard(phase, dayTa){
  const ad = findAdhikara(phase, dayTa, 'Day');
  const isToday = state.context && state.context.phase===phase && state.context.day===dayTa;
  const adhi = ad ? ad.adhikara : {icon:'❔',name:'Unknown'};
  const padu = ad ? ad.padu : {icon:'❔',name:'Unknown'};
  const target = `${phase.replace(' Moon','').toLowerCase()}-${dayTa}`;
  return `<article class="phase-week-card ${isToday?'today':''}">
    <div class="phase-week-head"><b>${DAY_EN[dayTa]}</b><span>${dayTa}</span></div>
    <div class="adhi-padu-pair">
      <div class="big-bird adhikara"><span class="emoji">${adhi.icon}</span><div class="role">Adhikara · In Charge</div><div class="bname">${adhi.name}</div></div>
      <div class="big-bird padu"><span class="emoji">${padu.icon}</span><div class="role">Padu · Away Bird</div><div class="bname">${padu.name}</div></div>
    </div>
    <a class="btn open-tree" href="#${target}">Open Day/Night Tree</a>
  </article>`;
}
function renderPhaseWeekdays(){
  const root=$('phaseWeekRoot'); if(!root || !APP) return;
  root.innerHTML = ['Rising Moon','Waning Moon'].map(phase=>`
    <section class="section"><div class="section-head"><h2>${phase}</h2><span class="badge">${phase==='Rising Moon'?'0° → 180°':'180° → 360°'}</span></div>
    <div class="phase-week-grid">${DAY_ORDER_TA.map(day=>phaseWeekCard(phase,day)).join('')}</div></section>`).join('');
}
function samamTreeHTML(phase, dayTa, period){
  const key = phaseKey(phase, period);
  const rows = APP.rows.filter(r=>r.dataset===key && r.day_ta===dayTa);
  return [1,2,3,4,5].map(s=>{
    const items = rows.filter(r=>r.samam_en===`Samam ${s}`);
    const total = items.reduce((a,b)=>a+b.minutes,0);
    return `<details><summary>Samam ${s} · ${total} min</summary>
      <div class="card-row" style="padding:12px">${items.map((r,i)=>`<div>${cardHTML({...r,index:i+1})}${innerPartsHTML(r.minutes)}</div>`).join('')}</div>
    </details>`;
  }).join('');
}
function renderPhaseDayNightTree(){
  const root=$('phaseDayNightRoot'); if(!root || !APP) return;
  root.innerHTML = ['Rising Moon','Waning Moon'].map(phase=>`
    <section class="section"><div class="section-head"><h2>${phase} · Weekday Trees</h2><span class="badge">Day/Night → Samam → Activities → Inner 5</span></div>
    <div class="phase-detail">${DAY_ORDER_TA.map(day=>{
      const id = `${phase.replace(' Moon','').toLowerCase()}-${day}`;
      const ad = findAdhikara(phase, day, 'Day');
      const adhi = ad ? ad.adhikara : {icon:'❔',name:'Unknown'};
      const padu = ad ? ad.padu : {icon:'❔',name:'Unknown'};
      return `<details id="${id}"><summary>${DAY_EN[day]} · ${day} · ${adhi.icon} Adhikara ${adhi.name} · ${padu.icon} Padu ${padu.name}</summary>
        <details open><summary>☀️ Day / பகல்</summary>${samamTreeHTML(phase, day, 'Day')}</details>
        <details><summary>🌙 Night / இரவு</summary>${samamTreeHTML(phase, day, 'Night')}</details>
      </details>`;
    }).join('')}</div></section>`).join('');
}

function applyLocation(sr){
  state.sunrise=sr;
  $('geoModal').classList.add('hide');
  $('geoStatus').textContent='Location enabled';
  $('geoDetails').textContent=`Sunrise ${fmt(sr)} · fixed 12hr day/night`;
  updateCurrent();
  if(!window._timer) window._timer=setInterval(updateCurrent,1000);
}
function requestGeo(){
  const err=$('geoError'); err.textContent='';
  if(!navigator.geolocation){err.textContent='Geolocation is not supported.';return;}
  navigator.geolocation.getCurrentPosition(pos=>applyLocation(approxSunrise(pos.coords.latitude,pos.coords.longitude)),()=>{err.textContent='Location permission needed for accurate timing.';},{enableHighAccuracy:true,timeout:10000,maximumAge:0});
}
async function init(){
  const safeClose = () => { const m=$('geoModal'); if(m) m.classList.add('hide'); };
  const allow=$('allowBtn'), locate=$('locateBtn'), skip=$('skipBtn');
  if(allow) allow.addEventListener('click',requestGeo);
  if(locate) locate.addEventListener('click',requestGeo);
  if(skip) skip.addEventListener('click',safeClose);

  APP = EMBEDDED_APP_DATA;
  renderPhaseWeekdays();
  renderPhaseDayNightTree();
  renderAdhikara();
  renderFullTree();

  const active=$('activeTreeRoot');
  if(active && !state.sunrise){
    active.innerHTML = '<div class="samam"><b>Location not enabled yet.</b><p class="lead">Click “Use My Location” for active live tree, or open the Full Tree below.</p></div>';
  }
}
init();
